const uploadsDir = "./uploads" // Directory where files are stored

// serveUploadsHandler is an HTTP handler that serves files from the 'uploadsDir'.
// It expects the filename as a path parameter after "/files/", e.g., /files/example.txt.
func serveUploadsHandler(w http.ResponseWriter, r *http.Request) {
	// Ensure the request method is GET
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Extract the filename from the URL path.
	// We expect paths like "/files/myimage.png", so we strip the prefix.
	filename := strings.TrimPrefix(r.URL.Path, "/files/")

	// Basic validation for filename to prevent common issues like empty or directory-like names.
	if filename == "" || strings.Contains(filename, "/") || strings.Contains(filename, "\\") {
		http.Error(w, "Invalid filename provided", http.StatusBadRequest)
		return
	}

	// Construct the full path to the file.
	// filepath.Join automatically handles platform-specific path separators.
	fullPath := filepath.Join(uploadsDir, filename)

	// --- Security Check: Prevent directory traversal attacks ---
	// Get the absolute path of the uploads directory.
	absUploadsDir, err := filepath.Abs(uploadsDir)
	if err != nil {
		fmt.Printf("Error getting absolute path for uploads directory: %v\n", err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	// Get the absolute path of the requested file.
	absFullPath, err := filepath.Abs(fullPath)
	if err != nil {
		fmt.Printf("Error getting absolute path for file %s: %v\n", fullPath, err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	// Ensure the requested file's absolute path starts with the uploads directory's absolute path.
	// This confirms the file is actually *inside* the uploads directory and not an external file.
	if !strings.HasPrefix(absFullPath, absUploadsDir) {
		http.Error(w, "Access denied: file outside permitted directory", http.StatusForbidden)
		return
	}
	// --- End Security Check ---

	// Open the file.
	file, err := os.Open(fullPath)
	if err != nil {
		if os.IsNotExist(err) {
			http.Error(w, "File not found", http.StatusNotFound)
		} else {
			// Log the actual error for server-side debugging.
			fmt.Printf("Error opening file %s: %v\n", fullPath, err)
			http.Error(w, "Could not open file", http.StatusInternalServerError)
		}
		return
	}
	defer file.Close() // Ensure the file is closed after serving.

	// Check if the path points to a directory.
	fileInfo, err := file.Stat()
	if err != nil {
		fmt.Printf("Error getting file info for %s: %v\n", fullPath, err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}
	if fileInfo.IsDir() {
		http.Error(w, "Cannot serve directories", http.StatusForbidden)
		return
	}

	// Determine the Content-Type.
	// First, try by file extension.
	contentType := mime.TypeByExtension(filepath.Ext(filename))
	if contentType == "" {
		// If extension-based detection fails, read a small chunk of the file
		// to let http.DetectContentType infer the type.
		buffer := make([]byte, 512) // Standard buffer size for http.DetectContentType
		n, err := file.Read(buffer)
		if err != nil && err != io.EOF {
			fmt.Printf("Error reading file for content type detection %s: %v\n", fullPath, err)
			http.Error(w, "Internal server error", http.StatusInternalServerError)
			return
		}
		contentType = http.DetectContentType(buffer[:n])

		// Reset the file pointer to the beginning after reading for detection,
		// so that io.Copy can serve the full file content.
		_, err = file.Seek(0, io.SeekStart)
		if err != nil {
			fmt.Printf("Error seeking file %s back to start: %v\n", fullPath, err)
			http.Error(w, "Internal server error", http.StatusInternalServerError)
			return
		}
	}

	// Set the Content-Type header.
	w.Header().Set("Content-Type", contentType)

	// Optionally, set Content-Length header for client progress indicators.
	w.Header().Set("Content-Length", fmt.Sprintf("%d", fileInfo.Size()))

	// Serve the file content by copying it directly to the response writer.
	_, err = io.Copy(w, file)
	if err != nil {
		// If an error occurs during io.Copy, headers might already have been sent,
		// so it's often too late to set an HTTP error status code.
		// Just log the error on the server side.
		fmt.Printf("Error serving file %s: %v\n", fullPath, err)
	}
}

func main() {
	// Create the uploads directory if it doesn't exist, for example files.
	if _, err := os.Stat(uploadsDir); os.IsNotExist(err) {
		err := os.Mkdir(uploadsDir, 0755) // Read/write for owner, read-only for others
		if err != nil {
			fmt.Printf("Failed to create uploads directory: %v\n", err)
			os.Exit(1)
		}
		fmt.Printf("Created directory: %s\n", uploadsDir)
	}

	// Create some example files for testing purposes.
	createExampleFile(filepath.Join(uploadsDir, "hello.txt"), []byte("Hello from Go's HTTP server!"))
	createExampleFile(filepath.Join(uploadsDir, "index.html"), []byte(`<!DOCTYPE html><html><head><title>Go File Server</title></head><body><h1>Served by Go!</h1><p>This is an HTML file.</p></body></html>`))
	createExampleFile(filepath.Join(uploadsDir, "example.json"), []byte(`{"name": "Go Server", "version": "1.0", "status": "running"}`))

	// Register our handler for paths starting with "/files/".
	// The trailing slash in "/files/" is important for http.StripPrefix later if used,
	// but with manual TrimPrefix it simply defines the base path.
	http.HandleFunc("/files/", serveUploadsHandler)

	fmt.Println("Server starting on http://localhost:8080")
	fmt.Println("Test with: http://localhost:8080/files/hello.txt")
	fmt.Println("Test with: http://localhost:8080/files/index.html")
	fmt.Println("Test with: http://localhost:8080/files/example.json")
	fmt.Println("Test with non-existent file: http://localhost:8080/files/nonexistent.png")

	// Start the HTTP server.
	err := http.ListenAndServe(":8080", nil)
	if err != nil {
		fmt.Printf("Server failed: %v\n", err)
	}
}

// createExampleFile is a helper to create example files if they don't exist.
func createExampleFile(path string, content []byte) {
	if _, err := os.Stat(path); os.IsNotExist(err) {
		err := os.WriteFile(path, content, 0644) // Read/write for owner, read-only for others
		if err != nil {
			fmt.Printf("Failed to create example file %s: %v\n", path, err)
		} else {
			fmt.Printf("Created example file: %s\n", path)
		}
	}
}